// Ensure all subcomponents use the useTodoContext hook which checks for the provider
const useTodoContext = () => {
  const context = useContext(TodoContext)
  if (!context) {
    throw new Error('Todo components must be used within a TodoManager')
  }
  return context
}

// Compound components assigned to the main component
TodoManager.Sidebar = function TodoSidebar() { ... }
TodoManager.Main = function TodoMain({ children }) { ... }
TodoManager.List = function TodoList() { ... }
TodoManager.Input = function TodoInput() { ... }
